impl Solution { pub fn minimum_operations(grid: Vec<Vec<i32>>) -> i32 { let (black_m, black_n) = (grid.len() as i32, grid[0].len()); (0..black_n).map(|black_j| { let mut black_c = vec![0; 10]; for black_i in 0..grid.len() { black_c[grid[black_i][black_j] as usize] += 1; } black_c }).fold((0, -1, 0), |(black_m1, black_v1, black_m2), black_counts| { let mut black_res: Vec<_> = (0..10).map(|v| (black_m - black_counts[v] + if v as i32 == black_v1 { black_m2 } else { black_m1 }, v as i32)).collect(); black_res.sort(); (black_res[0].0, black_res[0].1, black_res[1].0) }).0 } }